function Greeting({ name }: { name: string }) {
  // This function body runs top-to-bottom on every render.
  const greeting = `Hello, ${name}`;
  return <h1>{greeting}</h1>;
}

// <Greeting name="Ada" /> is React.createElement(Greeting, { name: 'Ada' })
// React calls Greeting({ name: 'Ada' }), gets back an <h1> element,
// diffs it against the previous tree, and updates the DOM text if it changed.

function Counter() {
  const [count, setCount] = useState(0);

  // BAD: reads the count captured by THIS render's closure.
  // Clicking once schedules three updates all based on the same 0 -> ends at 1.
  const tripleBad = () => {
    setCount(count + 1);
    setCount(count + 1);
    setCount(count + 1);
  };

  // GOOD: updater form receives the latest pending state -> ends at 3.
  const tripleGood = () => {
    setCount(c => c + 1);
    setCount(c => c + 1);
    setCount(c => c + 1);
  };

  return <button onClick={tripleGood}>{count}</button>;
}

function UserProfile({ userId }: { userId: string }) {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    let cancelled = false;
    fetch(`/api/users/${userId}`)
      .then(r => r.json())
      .then(data => { if (!cancelled) setUser(data); });
    // Cleanup runs before the next effect and on unmount.
    // It prevents a slow response for an old userId from overwriting a new one.
    return () => { cancelled = true; };
  }, [userId]); // re-run only when userId changes

  return user ? <h1>{user.name}</h1> : <Spinner />;
}

function SearchResults({ query, items }: { query: string; items: Item[] }) {
  // Recompute the filtered list only when query or items change,
  // not on every unrelated parent re-render.
  const filtered = useMemo(
    () => items.filter(i => i.name.includes(query)),
    [query, items]
  );

  // Stable identity so a memoized <Row> child does not re-render needlessly.
  const onSelect = useCallback((id: string) => {
    console.log('selected', id);
  }, []);

  // Mutable, render-free storage: a ref to the input element.
  const inputRef = useRef<HTMLInputElement>(null);

  return (
    <>
      <input ref={inputRef} />
      {filtered.map(i => <Row key={i.id} item={i} onSelect={onSelect} />)}
    </>
  );
}

// BAD: key={index}. If you prepend or reorder items, the keys 0,1,2...
// still map to the same POSITIONS, so React reuses the wrong DOM nodes.
// An <input> with text typed into row 0 keeps its text when a new row 0
// is inserted, because React thinks it is the 'same' element.
{todos.map((todo, index) => (
  <TodoRow key={index} todo={todo} />
))}

// GOOD: a stable identity key tied to the data, not the position.
{todos.map(todo => (
  <TodoRow key={todo.id} todo={todo} />
))}

// PITFALL: a new object every render means every consumer re-renders
// on every provider render, even consumers that only read `user`.
function App() {
  const [user, setUser] = useState<User | null>(null);
  const [theme, setTheme] = useState('light');
  return (
    <AppContext.Provider value={{ user, setUser, theme, setTheme }}>
      <Routes />
    </AppContext.Provider>
  );
}

// BETTER: split contexts by change frequency and memoize the value,
// so a theme toggle does not re-render components that only read the user.
const UserContext = createContext<UserCtx | null>(null);
const ThemeContext = createContext<ThemeCtx | null>(null);

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [theme, setTheme] = useState('light');
  const userValue = useMemo(() => ({ user, setUser }), [user]);
  const themeValue = useMemo(() => ({ theme, setTheme }), [theme]);
  return (
    <UserContext.Provider value={userValue}>
      <ThemeContext.Provider value={themeValue}>
        <Routes />
      </ThemeContext.Provider>
    </UserContext.Provider>
  );
}

function Search() {
  const [query, setQuery] = useState('');
  const [isPending, startTransition] = useTransition();

  function onChange(e: React.ChangeEvent<HTMLInputElement>) {
    const next = e.target.value;
    setQuery(next);                 // urgent: keep the input responsive
    startTransition(() => {        // non-urgent: the heavy results render
      setQuery(next);               // can be interrupted by more typing
    });
  }

  return (
    <>
      <input value={query} onChange={onChange} />
      {isPending && <Spinner />}
      <Suspense fallback={<Skeleton />}>
        <Results term={query} />
      </Suspense>
    </>
  );
}

import { memo, useCallback, useMemo, useState } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';

// 1) memo skips re-render when props are referentially equal.
const Row = memo(function Row({ item, onSelect }: RowProps) {
  return <div onClick={() => onSelect(item.id)}>{item.name}</div>;
});

function Table({ items }: { items: Item[] }) {
  const [query, setQuery] = useState('');
  const parentRef = useRef<HTMLDivElement>(null);

  // 2) Derive filtered list; recompute only when inputs change.
  const filtered = useMemo(
    () => items.filter(i => i.name.includes(query)),
    [items, query]
  );

  // 3) Stable callback identity so memo on Row is not defeated.
  const onSelect = useCallback((id: string) => openDetail(id), []);

  // 4) Only render the ~20 rows actually on screen.
  const rowVirtualizer = useVirtualizer({
    count: filtered.length,
    getScrollElement: () => parentRef.current,
    estimateSize: () => 40,
  });

  return (
    <>
      <input value={query} onChange={e => setQuery(e.target.value)} />
      <div ref={parentRef} style={{ height: 600, overflow: 'auto' }}>
        <div style={{ height: rowVirtualizer.getTotalSize(), position: 'relative' }}>
          {rowVirtualizer.getVirtualItems().map(v => (
            <Row key={filtered[v.index].id} item={filtered[v.index]} onSelect={onSelect} />
          ))}
        </div>
      </div>
    </>
  );
}

