import { useEffect, useState } from 'react';

export function useDebouncedValue<T>(value: T, delayMs: number): T {
  const [debounced, setDebounced] = useState(value);

  useEffect(() => {
    // Schedule an update to the latest value after the quiet period.
    const id = setTimeout(() => setDebounced(value), delayMs);
    // Cleanup runs before the next effect (i.e. on the next value change)
    // and on unmount, cancelling the pending update. This is what makes it
    // a debounce rather than a throttle, and prevents leaks.
    return () => clearTimeout(id);
  }, [value, delayMs]);

  return debounced;
}

// Usage: keep the input instant, debounce the expensive search.
function Search() {
  const [query, setQuery] = useState('');
  const debouncedQuery = useDebouncedValue(query, 300);

  // This effect only fires 300ms after the user stops typing.
  useEffect(() => {
    if (!debouncedQuery) return;
    const controller = new AbortController();
    fetch(`/api/search?q=${encodeURIComponent(debouncedQuery)}`, {
      signal: controller.signal,
    });
    return () => controller.abort();
  }, [debouncedQuery]);

  return <input value={query} onChange={e => setQuery(e.target.value)} />;
}

import { memo, useCallback, useState } from 'react';

type Todo = { id: string; text: string; done: boolean };

// 1) Each row is memoized: it re-renders only when its own props change.
const TodoRow = memo(function TodoRow({
  todo,
  onToggle,
}: {
  todo: Todo;
  onToggle: (id: string) => void;
}) {
  return (
    <li>
      <input type="checkbox" checked={todo.done} onChange={() => onToggle(todo.id)} />
      {todo.text}
    </li>
  );
});

// 2) The input lives in its own component, so its keystroke state is
//    isolated and never re-renders the list.
function NewTodoInput({ onAdd }: { onAdd: (text: string) => void }) {
  const [text, setText] = useState('');
  return (
    <input
      value={text}
      onChange={e => setText(e.target.value)}
      onKeyDown={e => {
        if (e.key === 'Enter' && text.trim()) {
          onAdd(text.trim());
          setText('');
        }
      }}
    />
  );
}

export function TodoList() {
  const [todos, setTodos] = useState<Todo[]>([]);

  // 3) Stable callbacks so memo on TodoRow is not defeated.
  const onAdd = useCallback((text: string) => {
    setTodos(prev => [...prev, { id: crypto.randomUUID(), text, done: false }]);
  }, []);

  const onToggle = useCallback((id: string) => {
    setTodos(prev =>
      prev.map(t => (t.id === id ? { ...t, done: !t.done } : t))
    );
  }, []);

  return (
    <div>
      <NewTodoInput onAdd={onAdd} />
      <ul>
        {todos.map(todo => (
          <TodoRow key={todo.id} todo={todo} onToggle={onToggle} />
        ))}
      </ul>
    </div>
  );
}
